using System;
using UnityEngine;

namespace vynscastingmod.Objects
{
    public struct Overlays
    {
        public static void InitOverlays()
        {
            cgtDefault.LoadImage(cgtDefaultBytes);
            cgtPink.LoadImage(cgtPinkBytes);
            leaderboardPart.LoadImage(leaderboardBytes);
        }
        
        // store our overlays as base64 bytes
        
        public static Texture2D cgtDefault = new Texture2D(1,1), cgtPink = new Texture2D(1,1), leaderboardPart = new Texture2D(1,1);
        public static Texture2D customScoreboard = new Texture2D(1,1), customLeaderboard = new Texture2D(1,1);

        public static byte[] leaderboardBytes = Convert.FromBase64String(
            "");
        
        public static byte[] cgtDefaultBytes = Convert.FromBase64String("");
        
        public static byte[] cgtPinkBytes = Convert.FromBase64String("");
    }
}